// Gate 2 retrieval-quality corpus: 200 first-person memories across 5 themes
// (40 each) + 30 evaluation queries (6 per theme). Each memory is tagged with
// `theme:<name>` so the test can compute precision@5 and recall@10 by checking
// whether returned memories carry the matching theme tag.
//
// Themes are intentionally distinct topics that a real power-user might mix
// across months of Spine usage. Memories vary in length and phrasing so the
// scorer doesn't filter them all the same way and the retriever has to do
// real semantic work rather than keyword-matching.

export type Theme = 'tech' | 'travel' | 'cooking' | 'fitness' | 'books';

export const THEME_TAG_PREFIX = 'recall-quality:theme:';

